INSERT INTO public.career_tracks VALUES (31, 'SOC Operations', 'Security Operations Center career pathway focusing on real-time threat monitoring, analysis, and response', 'Comprehensive career progression from entry-level analyst to executive security leadership roles', '2025-05-29 16:58:03.076494');
INSERT INTO public.career_tracks VALUES (35, 'Cybersecurity Architecture & Engineering', 'Career pathway focusing on security system design, implementation, and architectural solutions', 'Complete progression from technical security implementation to enterprise-level security architecture and strategic system design', '2025-05-29 17:09:40.482928');
INSERT INTO public.career_tracks VALUES (37, 'Cloud and Infrastructure Security', 'Career pathway focusing on cloud security, infrastructure protection, and hybrid environment security management', 'Complete progression from cloud support roles to executive infrastructure security leadership with authentic NICE Framework work role alignments across multiple categories', '2025-05-29 17:12:37.723538');
INSERT INTO public.career_tracks VALUES (38, 'Identity and Access Management', 'Career pathway focusing on access control, identity governance, and user lifecycle management', 'Complete progression from basic access control support to executive identity strategy leadership', '2025-05-29 17:17:22.066584');
INSERT INTO public.career_tracks VALUES (39, 'OT (Operational Technology) Security', 'Career pathway focusing on industrial control systems, SCADA security, and operational technology protection', 'Complete progression from OT support roles to executive operational security leadership with focus on ICS/SCADA environments', '2025-05-29 17:21:48.784949');
INSERT INTO public.career_tracks VALUES (41, 'Cybersecurity Education & Training', 'Career pathway focusing on cybersecurity education, workforce development, and instructional design', 'Complete progression from associate instructor roles to executive workforce development leadership', '2025-05-29 17:27:05.380482');
INSERT INTO public.career_tracks VALUES (42, 'Executive Leadership CISO Track', 'Specialized career pathway focused on preparation for Chief Information Security Officer roles and executive cybersecurity leadership', 'Strategic progression from senior program management to executive CISO leadership, starting at senior level due to experience requirements', '2025-05-29 17:28:23.847584');
INSERT INTO public.career_tracks VALUES (43, 'Program and Project Management', 'Career pathway for cybersecurity professionals focused on project coordination, program management, and strategic portfolio oversight', 'Progression from project coordination to executive program leadership with responsibility for cybersecurity initiatives and strategic alignment', '2025-05-29 17:30:21.575614');
INSERT INTO public.career_tracks VALUES (44, 'Technology Research and Tool Development', 'Career pathway for cybersecurity professionals focused on research, innovation, and development of security tools and technologies', 'Progression from junior tool development to executive research leadership with responsibility for cybersecurity innovation and R&D strategy', '2025-05-29 17:31:30.004142');
INSERT INTO public.career_tracks VALUES (45, 'Security Automation and Orchestration', 'Career pathway for cybersecurity professionals focused on automating security processes, developing SOAR platforms, and orchestrating complex security workflows', 'Progression from automation analysis to executive strategy with responsibility for enterprise-wide security automation and orchestration initiatives', '2025-05-29 17:33:53.098718');
INSERT INTO public.career_tracks VALUES (46, 'Customer Facing Security Roles', 'Career pathway for cybersecurity professionals focused on client engagement, technical sales, and customer success in security solutions', 'Progression from customer support to executive customer security leadership with responsibility for client relationships and security solution delivery', '2025-05-29 17:43:53.423413');
INSERT INTO public.career_tracks VALUES (48, 'Privacy Policy Legal Affairs', 'Career pathway for cybersecurity professionals focused on privacy law, policy development, regulatory compliance, and legal aspects of cybersecurity', 'Progression from privacy analysis to executive legal leadership with responsibility for enterprise privacy strategy and regulatory compliance', '2025-05-29 17:52:22.450693');
